import React from "react";
import BigTitlte from "../../subcomp/BigTitlte";
import Social from "../../subcomp/Social";
import "./contact.scss";
import { motion } from "framer-motion";
import Form from "../../subcomp/Form/Form";

const Contact = () => {
  const PageTrans = {
    in: {
      opacity: 1,
      y: 0,
    },
    out: {
      opacity: 0,
      y: "-100%",
    },
    duration: {
      duration: 3,
    },
  };
  return (
    <motion.div
      className="contact"
      variants={PageTrans}
      initial="out"
      animate="in"
      exit="out"
      duration="duration"
    >
      <div className="top">
        <Social />
      </div>
      <div className="head">
        <BigTitlte text="Contact" top="10%" right="10%" />
      </div>
      <div className="bottom">
        <div className="form">
          <Form />
        </div>
      </div>
    </motion.div>
  );
};

export default Contact;
