import React from "react";
import BigTitlte from "../../subcomp/BigTitlte";
import Social from "../../subcomp/Social";
import "./skill.scss";
import { motion } from "framer-motion";
import Skill from "../../subcomp/Skill/Skill";

const PageTrans = {
  in: {
    opacity: 1,
    y: 0,
    duration: 3,
  },
  out: {
    opacity: 0,
    y: "50%",
    duration: 3,
  },
};

const Skills = () => {
  return (
    <motion.div
      className="skill-main"
      variants={PageTrans}
      initial="out"
      animate="in"
      exit="out"
    >
      <div className="top">
        <Social />
      </div>
      <div className="head">
        <BigTitlte text="Skills" top="10%" right="10%" />
      </div>
     <div className="skill-comp">
       <Skill />
     </div>
    </motion.div>
  );
};

export default Skills;
