import { motion } from "framer-motion";
import React from "react";
import { NavLink } from "react-router-dom";
import styled from "styled-components";
import { Github } from "../../subcomp/AllSvgs";
import "./Card.scss";

const Box = styled(motion.li)`
  width: 250px;
  height: 370px;
  background-color: #65ccb8;
  color: #182628;
  padding: 1.5rem 2rem;
  margin-right: 3rem;
  border-radius: 0 50px 0 50px;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  border: 1px solid #3b945e;
  transition: all 0.2s ease;
  &:hover {
    background-color: #3b945e;
    color: white;
    border: 1px solid #182628;
  }
`;
const Title = styled.h2`
  font-size: 24px;
  size: 60px;
`;

const Description = styled.h2`
  font-size: 14px;
  font-family: cursive;
  font-weight: 300;
`;

const Footer = styled.footer`
  display: flex;
  justify-content: space-between;
`;

const Image = styled.image`
  img {
    margin-top: 10px;
    width: 210px;
    border-radius: 12px;
    margin-left: -8px;
    @media (max-width: 1152px) {
      width: 190px;
      margin-left: 8px;
    }
    @media (max-width: 1092px) {
      width: 180px;
    }
  }
`;

const Git = styled(NavLink)`
  color: inherit;
  text-decoration: none;
  margin-top: 20px;
  margin-left: 20px;
  ${Box}:hover & {
    & > * {
      fill: #182628;
    }
  }
`;

// Framer motion configuration
const Item = {
  hidden: {
    scale: 0,
  },
  show: {
    scale: 1,
    transition: { type: "spring", duration: 0.5 },
  },
};

const Card = (props) => {
  const { id, name, description, github, img } = props.data;

  return (
    <>
      <Box key={id} variants={Item} className="box1">
        <Title className="title">{name}</Title>
        <Image>
          <img src={img} alt="" />
        </Image>
        <Description className="desc">{description}</Description>
        <Footer>
          <Git to={{ pathname: `${github}` }} target="_blank">
            <Github width={30} height={30} className="git" />
          </Git>
        </Footer>
      </Box>
    </>
  );
};

export default Card;
