import React from "react";
import styled from "styled-components";
import { motion } from "framer-motion";

import { data } from "./data";
import Card from "./Card";

import BigTitlte from "../../subcomp/BigTitlte";
import Social from "../../subcomp/Social";
import "./Project.scss";

const Box = styled.div`
  background-color: white;

  height: 100vh;
  position: relative;
  display: flex;
  align-items: center;
`;

const Main = styled(motion.ul)`
  position: fixed;
  top: 13rem;

  
  display: grid;
  gap: 2rem;
  grid-template-columns: repeat(3, 1fr);

  color: white;
  @media (max-width: 1060px) {
    max-width: 70vw;
    flex-wrap: wrap;
    height: 60vh;
    overflow: scroll;
    margin-top: 50px;
  }
  @media (max-width: 670px) {
    overflow: scroll;
    width: 600px;
    margin-top: 50px;
    display: flex;
    max-width: 500px;
    margin-left:50px;
  }
`;

// Framer-motion Configuration
const container = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,

    transition: {
      staggerChildren: 0.5,
      duration: 0.5,
    },
  },
};

const Project = () => {
  return (
    <div className="project">
      <div className="social">
        <Social />
      </div>
      <Box>
        <Main
          variants={container}
          initial="hidden"
          animate="show"
          className="box"
        >
          {data.map((d) => (
            <Card key={d.id} data={d} />
          ))}
        </Main>

        <BigTitlte text="Projects" top="10%" right="10%" />
      </Box>
    </div>
  );
};

export default Project;
