import React, { useRef, useEffect } from "react";
import { init } from "ityped";
import "./intro.scss";
import Social from "../../subcomp/Social";
import { motion } from "framer-motion";
import Logo from "../../subcomp/Logo";

import "../../subcomp/global.scss";
import AK from "../../assets/AK.png";

export default function Intro() {
  const textRef = useRef();

  useEffect(() => {
    init(textRef.current, {
      showCursor: true,
      backDelay: 1500,
      typeSpeed: 200,
      backSpeed: 200,
      strings: ["Developer", "Freelancer"],
    });
  });
  const PicTrans = {
    hidden: {
      opacity: 0,
      x: -700,
    },
    visible: {
      opacity: 1,
      x: 0,
      transition: { delay: 0.15, duration: 0.75, type: "tween" },
    },
  };
  const PageTrans = {
    in: {
      opacity: 1,
      y: 0,
    },
    out: {
      opacity: 0,
      y: "-100%",
    },
    duration: {
      duration: 3,
    },
  };
  return (
    <motion.div
      className="intro"
      variants={PageTrans}
      initial="out"
      animate="in"
      exit="out"
      duration="duration"
    >
      <div className="logo">
        <Logo />
      </div>
      <div className="top">
        <Social />
      </div>
      <div className="bottom">
        <motion.div
          className="pic"
          variants={PicTrans}
          initial="hidden"
          animate="visible"
        >
          <img src={AK} alt="" />
        </motion.div>
        <div className="text">
          <div className="text1">Hy, I am</div>
          <div className="text2">Aneesh Kumar</div>
          <div className="text3">
            And I'm a <span ref={textRef}></span>
          </div>
          <h4>
            <i>
              "A constant, hardworking and goal oriented guy having strong
              <br />
              technical and problem solving skills."
            </i>
          </h4>
        </div>
      </div>
    </motion.div>
  );
}
