import { motion } from "framer-motion";
import React from "react";
import { NavLink } from "react-router-dom";
import styled from "styled-components";
import { Codechef, Github, Twitter, Instagram } from "./AllSvgs";

const Icons = styled.div`
  display: flex;

  align-items: center;

  position: fixed;

  z-index: 3;

  color: #182628;

  & > *:not(:last-child) {
    margin: 5px 6px;
  }
`;

const Line = styled(motion.span)`
  width: 8rem;
  height: 2px;
  background-color: #182628;
`;

const SocialIcons = (props) => {
  return (
    <Icons>
      <motion.div
        initial={{ transform: "scale(0)" }}
        animate={{ scale: [0, 1, 1.5, 1] }}
        transition={{ type: "spring", duration: 1, delay: 1 }}
      >
        <NavLink
          style={{ color: "inherit" }}
          target="_blank"
          to={{ pathname: "https://github.com/aneesh-kumar1" }}
        >
          <Github width={25} height={25} />
        </NavLink>
      </motion.div>
      <motion.div
        initial={{ transform: "scale(0)" }}
        animate={{ scale: [0, 1, 1.5, 1] }}
        transition={{ type: "spring", duration: 1, delay: 1.2 }}
      >
        <NavLink
          style={{ color: "inherit" }}
          target="_blank"
          to={{ pathname: "https://twitter.com/AneeshK1029" }}
        >
          <Twitter width={25} height={25} />
        </NavLink>
      </motion.div>
      <motion.div
        initial={{ transform: "scale(0)" }}
        animate={{ scale: [0, 1, 1.5, 1] }}
        transition={{ type: "spring", duration: 1, delay: 1.4 }}
      >
        <NavLink
          style={{ color: "inherit" }}
          target="_blank"
          to={{ pathname: "https://www.codechef.com/users/aneesh1029" }}
        >
          <Codechef width={25} height={25} />
        </NavLink>
        <NavLink
          style={{ color: "inherit" }}
          target="_blank"
          to={{ pathname: "https://www.instagram.com/aneesh1029/" }}
        >
          <Instagram width={25} height={25} />
        </NavLink>
      </motion.div>
      <motion.div
        initial={{ transform: "scale(0)" }}
        animate={{ scale: [0, 1, 1.5, 1] }}
        transition={{ type: "spring", duration: 1, delay: 1.6 }}
      ></motion.div>

      <Line
        color={props.theme}
        initial={{
          width: 0,
        }}
        animate={{
          width: "8rem",
        }}
        transition={{
          type: "spring",
          duration: 1,
          delay: 0.8,
        }}
      />
    </Icons>
  );
};

export default SocialIcons;
