import React, { useState, useRef } from "react";
import './form.scss'
import emailjs from "emailjs-com";

const Form = () => {
  const formRef = useRef();
  const [done, setDone] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    emailjs
      .sendForm(
        "service_hkhphzw",
        "template_8afvnlv",
        formRef.current,
        "user_S9gZo80D1oGwrqsdSALYS"
      )
      .then(
        (result) => {
          console.log(result.text);
          setDone(true);
        },
        (error) => {
          console.log(error.text);
        }
      );
  };
  return (
    <>
      <div className="form">
        <p>
          <b>Get in touch.</b>
        </p>
        <form ref={formRef} onSubmit={handleSubmit} className="form-in">
          <input type="text" placeholder="Name" name="name" className="input" required />
          <input
            type="text"
            placeholder="Subject"
            name="subject"
            className="input"
            required
          />
          <input
            type="text"
            placeholder="Email"
            name="email"
            className="input"
            required
          />
          <textarea
            rows="5"
            placeholder="Message"
            name="message"
            className="textarea"
            required
          />
          <button className="btn">Submit</button>
          {done && "Thank you..."}
        </form>
      </div>
    </>
  );
};

export default Form;
