import React, { useState } from "react";
//All the svg files
import Home from "../../assets/home-solid.svg";
import Team from "../../assets/social.svg";
import Projects from "../../assets/starred.svg";
import AllMail from "../../assets/All Mail.svg";
import Documents from "../../assets/draft.svg";
import styled from "styled-components";
import { NavLink } from "react-router-dom";
import "./navbar.scss";

const Container = styled.div`
  position: fixed;
  background-color: #65ccb8 .active {
    border-right: 6px solid #182628;
  }
`;
//menu button
const Button = styled.button`
  background-color: white;
  border: none;
  width: 50px;
  
  border-radius: 50%;
  margin: 20px 0 0 10px;
  cursor: pointer;

  display: flex;
  justify-content: center;
  align-items: center;

  position: relative;

  &::before,
  &::after {
    content: "";
    background-color: #65ccb8;
    height: 2px;
    
    width: 1rem;
    position: absolute;
    transition: all 0.3s ease;
  }

  &::before {
    top: ${(props) => (props.clicked ? "1" : "1rem")};
    transform: ${(props) => (props.clicked ? "rotate(135deg)" : "rotate(0)")};
  }

  &::after {
    top: ${(props) => (props.clicked ? "1" : "1.5rem")};
    transform: ${(props) => (props.clicked ? "rotate(-135deg)" : "rotate(0)")};
  }
`;

const SlickBar = styled.ul`
  color: #182628;
  list-style: none;
  display: flex;
  flex-direction: column;
  align-items: center;
  background-color: #65ccb8;
  padding: 2rem 0;
  margin-top: 100px;
  position: absolute;
  top: 6rem;
  left: 0;

  width: ${(props) => (props.clicked ? "12rem" : "3.5rem")};
  transition: all 0.5s ease;
  border-radius: 0 30px 30px 0;
`;

const Item = styled(NavLink)`
  text-decoration: none;
  color: #182628;
  width: 100%;
  padding: 1rem 0;
  cursor: pointer;

  display: flex;
  padding-left: 1rem;

  &:hover {
    border-right: 4px solid #182628;
    color: #182628;

    img {
      filter: invert(100%) sepia(0%) saturate(0%) hue-rotate(93deg)
        brightness(103%) contrast(103%);
    }
  }

  img {
    width: 1.2rem;
    height: auto;
  }
`;

const Text = styled.span`
  width: ${(props) => (props.clicked ? "100%" : "0")};
  overflow: hidden;
  color: #182628;
  font-weight: 300;
  margin-left: ${(props) => (props.clicked ? "1.5rem" : "0")};
  transition: all 0.3s ease;
`;

const Sidebar = () => {
  const [click, setClick] = useState(false);
  const handleClick = () => setClick(!click);

  return (
    <Container className="container">
      <Button
        className="btn"
        clicked={click}
        onClick={() => handleClick()}
      ></Button>

      <SlickBar clicked={click}>
        <Item
          onClick={() => setClick(false)}
          exact
          activeClassName="active"
          to="/"
        >
          <img src={Home} alt="Home" />
          <Text clicked={click}>Home</Text>
        </Item>
        <Item
          onClick={() => setClick(false)}
          activeClassName="active"
          to="/About"
        >
          <img src={Team} alt="About" />
          <Text clicked={click}>About</Text>
        </Item>
        <Item
          onClick={() => setClick(false)}
          activeClassName="active"
          to="/Project"
        >
          <img src={Documents} alt="Projects" />
          <Text clicked={click}>Project</Text>
        </Item>
        <Item
          onClick={() => setClick(false)}
          activeClassName="active"
          to="/Skills"
        >
          <img src={Projects} alt="Skills" />
          <Text clicked={click}>Skills</Text>
        </Item>
        <Item
          onClick={() => setClick(false)}
          activeClassName="active"
          to="/Contact"
        >
          <img src={AllMail} alt="Contact" />
          <Text clicked={click}>Contact</Text>
        </Item>
      </SlickBar>
    </Container>
  );
};

export default Sidebar;
